// SHAREABLE URL SYSTEM
// ═══════════════════════════════════════════════════════════════════════════════

function serializeState() {
  const p = new URLSearchParams();
  if (state.preset !== 'balanced')  p.set('preset', state.preset);
  if (state.preset === 'custom') {
    const w = state.weights;
    p.set('w', [w.snow, w.size, w.value, w.crowd].join(','));
    if (state.skillLevel && state.skillLevel !== 'mixed') p.set('skill', state.skillLevel);
  }
  if (state.verticalFilter !== 'any')  p.set('vert',  state.verticalFilter);
  if (state.passFilter  !== 'All')     p.set('pass',  state.passFilter);
  if (state.stateFilter !== 'All')     p.set('st',    state.stateFilter);
  if (state.sortBy      !== 'planner') p.set('sort',  state.sortBy);
  if (state.nightOnly)                 p.set('night', '1');
  if (state.howFar > 0)                p.set('howfar', state.howFar);
  // maxDrive legacy URL param removed
  if (state.maxPrice > 0)              p.set('price', state.maxPrice);
  if (state.skiDays  !== 5)            p.set('days',  state.skiDays);
  if (state.origin) {
    p.set('lat', state.origin.lat.toFixed(4));
    p.set('lon', state.origin.lon.toFixed(4));
    p.set('loc', state.origin.label);
  }
  return p;
}

// Returns true if URL contained state to restore
function applyUrlState() {
  const p = new URLSearchParams(window.location.search);
  if (!p.toString()) return false;

  const preset = p.get('preset');
  if (preset && PRESETS[preset]) {
    state.preset  = preset;
    state.weights = { ...PRESETS[preset] };
  }
  if (preset === 'custom') {
    const wStr = p.get('w');
    if (wStr) {
      const parts = wStr.split(',').map(Number);
      if (parts.length === 5 && parts.every(n => !isNaN(n) && n >= 0)) {
        // Legacy 5-part URL [snow, drive, size, value, crowd] — drop drive
        const [snow, , size, value, crowd] = parts;
        state.weights = { ...state.weights, snow, size, value, crowd };
      } else if (parts.length === 4 && parts.every(n => !isNaN(n) && n >= 0)) {
        const [snow, size, value, crowd] = parts;
        state.weights = { ...state.weights, snow, size, value, crowd };
      }
    }
  }
  if (p.has('vert')  && ['any','small','sweet','mid','big'].includes(p.get('vert'))) state.verticalFilter = p.get('vert');
  if (p.has('pass')  && UNIQUE_PASSES.includes(p.get('pass')))  state.passFilter  = p.get('pass');
  if (p.has('st')    && UNIQUE_STATES.includes(p.get('st')))    state.stateFilter = p.get('st');
  if (p.has('sort'))  state.sortBy    = p.get('sort');
  if (p.has('night'))   state.nightOnly   = true;
  if (p.has('howfar'))  state.howFar = Math.min(2, Number(p.get('howfar')) || 0);
  // maxDrive legacy URL param — ignored, howFar takes precedence
  if (p.has('price')) { state.maxPrice = Number(p.get('price')) || 0; state.priceRange = 0; } // legacy URL compat
  if (p.has('days'))  state.skiDays   = Math.max(1, Number(p.get('days')) || 5);
  if (p.has('skill') && ['beginner','mixed'].includes(p.get('skill'))) state.skillLevel = p.get('skill');

  const lat = parseFloat(p.get('lat'));
  const lon = parseFloat(p.get('lon'));
  const loc = p.get('loc');
  if (!isNaN(lat) && !isNaN(lon) && loc) {
    state.origin = { lat, lon, label: loc };
  }
  return true;
}

// ─── URL slug routing (/report/<slug>) ───────────────────────────────────────
function slugify(name) {
  return name
    .toLowerCase()
    .replace(/[''‘’]/g, '') // strip apostrophes: "Pat's Peak" → "pats-peak"
    .replace(/[^a-z0-9]+/g, '-')       // non-alphanumeric to hyphens
    .replace(/^-+|-+$/g, '');          // trim leading/trailing hyphens
}

function findResortBySlug(slug) {
  return RESORTS.find(r => slugify(r.name) === slug || r.id === slug) || null;
}

function getReportSlug() {
  const m = window.location.pathname.match(/^\/report\/([^/?#]+)/);
  return m ? m[1] : null;
}

// Push a /report/<slug> URL when a resort detail card opens
function pushReportUrl(resort) {
  const slug   = slugify(resort.name);
  const params = serializeState();
  const qs     = params.toString() ? '?' + params : '';
  history.pushState({ reportSlug: slug }, resort.name + ' — Where To Ski?!', '/report/' + slug + qs);
  document.title = resort.name + ' — Where To Ski?!';
}

// Pop back to the root URL (called when detail closes or back is pressed)
function popToRoot() {
  const params = serializeState();
  const qs     = params.toString() ? '?' + params : '';
  history.replaceState({ reportSlug: null }, 'Where To Ski?!', '/' + qs);
  document.title = 'Where To Ski?!';
}

const pushUrlDebounced = debounce(() => {
  const p    = serializeState();
  const qs   = p.toString() ? '?' + p : '';
  // If a resort detail is open, keep the /report/<slug> path; otherwise use /
  const base = state.selectedId
    ? '/report/' + slugify(RESORTS.find(r => r.id === state.selectedId)?.name || state.selectedId)
    : '/';
  history.replaceState(null, '', base + qs);
}, 600);

function copyShareLink() {
  const p   = serializeState();
  const url = `${location.origin}${location.pathname}${p.toString() ? '?' + p : ''}`;
  const doToast = () => showToast('Link copied — share with your crew!', 3200);
  if (navigator.clipboard?.writeText) {
    navigator.clipboard.writeText(url).then(doToast).catch(() => fallbackCopy(url));
  } else { fallbackCopy(url); }
}
function fallbackCopy(text) {
  const ta = Object.assign(document.createElement('textarea'), {
    value: text, style: 'position:fixed;opacity:0',
  });
  document.body.appendChild(ta); ta.select();
  try { document.execCommand('copy'); showToast('Link copied!', 3200); } catch(e) {}
  document.body.removeChild(ta);
}

