function historyDateRange() {
  const end   = new Date(); end.setDate(end.getDate() - 1);       // yesterday
  const start = new Date(end); start.setDate(end.getDate() - 6);  // 7 days back
  const fmt   = d => d.toISOString().slice(0, 10);
  return { start: fmt(start), end: fmt(end) };
}

async function fetchHistory(resort) {
  const cached = historyCache.get(resort.id);
  if (cached && Date.now() - cached.ts < HIST_TTL) return cached;
  try {
    const { start, end } = historyDateRange();
    const url = `https://archive-api.open-meteo.com/v1/archive?` +
      `latitude=${resort.lat}&longitude=${resort.lon}` +
      `&start_date=${start}&end_date=${end}` +
      `&daily=snowfall_sum&timezone=America%2FNew_York`;
    const res  = await fetchWithTimeout(url, {}, 10000);
    const data = await res.json();
    const days  = (data.daily?.time || []).map((date, i) => ({
      date,
      snow: Math.round((data.daily.snowfall_sum?.[i] || 0) * 10) / 10,
    }));
    const total = Math.round(days.reduce((s, d) => s + d.snow, 0) * 10) / 10;
    const entry = { total, days, ts: Date.now() };
    historyCache.set(resort.id, entry);
    return entry;
  } catch (e) { return null; }
}

async function ensureHistory(resorts) {
  const queue = resorts.filter(r => !historyCache.has(r.id));
  await Promise.all(Array.from({ length: 6 }, async () => {
    while (queue.length) {
      const r = queue.shift();
      if (r) await fetchHistory(r);
    }
  }));
  saveHistoryCache();
}

function loadHistoryCache() {
  try {
    const raw = sessionStorage.getItem('ski-hist-cache');
    if (!raw) return;
    const now = Date.now();
    Object.entries(JSON.parse(raw)).forEach(([id, entry]) => {
      if (now - entry.ts < HIST_TTL) historyCache.set(id, entry);
    });
  } catch (e) { /* ignore */ }
}

function saveHistoryCache() {
  try {
    const obj = {};
    historyCache.forEach((v, k) => { obj[k] = v; });
    sessionStorage.setItem('ski-hist-cache', JSON.stringify(obj));
  } catch (e) { /* quota exceeded */ }
}

// ─── Live conditions (via /api/conditions → Claude) ───────────────────────────

function loadConditionsCache() {
  try {
    const raw = sessionStorage.getItem('ski-conditions-cache');
    if (!raw) return;
    const now = Date.now();
    Object.entries(JSON.parse(raw)).forEach(([id, entry]) => {
      if (now - entry.ts < CONDITIONS_TTL) conditionsCache.set(id, entry);
    });
  } catch (e) { /* ignore */ }
}

function saveConditionsCache() {
  try {
    const obj = {};
    conditionsCache.forEach((v, k) => { obj[k] = v; });
    sessionStorage.setItem('ski-conditions-cache', JSON.stringify(obj));
  } catch (e) { /* quota exceeded */ }
}

async function fetchConditions(resort) {
  const cached = conditionsCache.get(resort.id);
  const ttl = cached?.source === 'liftie' ? LIFTIE_TTL : CONDITIONS_TTL;
  if (cached && Date.now() - cached.ts < ttl) return cached.data;

  // ── Path A: Liftie (fast, free, ~200ms) ────────────────────────────────────
  const liftieSlug = LIFTIE_SLUGS[resort.id];
  if (liftieSlug) {
    try {
      const res = await fetchWithTimeout(`/api/liftie?slug=${liftieSlug}`, 6000);
      if (res.ok) {
        const json = await res.json();
        if (!json.error && json.liftsTotal != null) {
          const data = {
            liftsOpen:   json.liftsOpen  ?? null,
            liftsTotal:  json.liftsTotal ?? null,
            baseDepth:   null,
            newSnow24h:  null,
            newSnow48h:  null,
            trailsOpen:  null,
            trailsTotal: null,
            surface:     null,
            reportDate:  null,
            notes:       null,
            fetchedAt:   Date.now(),
            source:      'liftie',
          };
          conditionsCache.set(resort.id, { ts: Date.now(), data, source: 'liftie' });
          saveConditionsCache();
          return data;
        }
      }
    } catch (e) {
      console.warn('[conditions/liftie] failed for', resort.name, e.message);
    }
  }

  // ── Path B: Claude scraper fallback ────────────────────────────────────────
  if (!resort.website) {
    conditionsCache.set(resort.id, { ts: Date.now(), data: null, source: 'none' });
    return null;
  }
  try {
    const res = await fetchWithTimeout('/api/conditions', 16000, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ resortId: resort.id, name: resort.name, url: resort.website }),
    });
    const json = await res.json();
    const data = json.conditions ? { ...json.conditions, source: 'claude' } : null;
    conditionsCache.set(resort.id, { ts: Date.now(), data, source: 'claude' });
    saveConditionsCache();
    return data;
  } catch (e) {
    console.warn('[conditions/claude] failed for', resort.name, e.message);
    conditionsCache.set(resort.id, { ts: Date.now(), data: null, source: 'none' });
    return null;
  }
}

async function ensureConditions(resorts) {
  const queue = resorts.filter(r => r.website && !conditionsCache.has(r.id));
  if (!queue.length) return;
  // Concurrency = 5: each call is I/O-bound (network), not CPU
  await Promise.all(Array.from({ length: 5 }, async () => {
    while (queue.length) {
      const r = queue.shift();
      if (r) await fetchConditions(r);
    }
  }));
}

// Priority fetch for a single resort — called immediately on detail card open
// Re-renders detail card as soon as its own data arrives, no waiting for others
async function fetchConditionsForDetail(resort) {
  if (!resort?.website) return;
  if (conditionsCache.get(resort.id)?.data) return; // already have it
  await fetchConditions(resort);
  renderDetail(); // re-render detail card only — quiet, no full re-render
}

// ── Conditions quality index (0–1) for scoring ──────────────────────────────
// Combines: trails open %, base depth vs 60" ideal, new snow 24h bonus
function conditionsIndex(resort) {
  const c = conditionsCache.get(resort.id)?.data;
  if (!c) return null; // null = not yet loaded, caller degrades gracefully

  let score = 0.5; // neutral baseline

  // Trails open %: 0→0 pts, 100%→0.35 pts
  if (c.trailsOpen != null && c.trailsTotal > 0) {
    score += (c.trailsOpen / c.trailsTotal) * 0.35;
  }

  // Base depth: 0"→-0.15, 30"→0, 60"→+0.15 (capped)
  if (c.baseDepth != null) {
    const depthScore = Math.min(1, c.baseDepth / 60);
    score += (depthScore - 0.5) * 0.3;
  }

  // New snow 24h bonus: 0"→0, 12"→+0.15 (fresh snow is exciting)
  if (c.newSnow24h != null && c.newSnow24h > 0) {
    score += Math.min(0.15, c.newSnow24h / 12 * 0.15);
  }

  return Math.max(0, Math.min(1, score));
}

// Human-readable conditions summary for UI
function conditionsSummary(resort) {
  const c = conditionsCache.get(resort.id)?.data;
  if (!c) return null;
  const parts = [];
  if (c.baseDepth    != null) parts.push(`${c.baseDepth}" base`);
  if (c.newSnow24h   != null && c.newSnow24h > 0) parts.push(`${c.newSnow24h}" new`);
  if (c.trailsOpen   != null && c.trailsTotal  != null) parts.push(`${c.trailsOpen}/${c.trailsTotal} trails open`);
  if (c.liftsOpen    != null && c.liftsTotal   != null) parts.push(`${c.liftsOpen}/${c.liftsTotal} lifts`);
  if (c.surface) parts.push(c.surface);
  return parts.length ? parts.join(' · ') : null;
}



// Inline SVG bar sparkline — one bar per day, colour-coded by intensity
function snowSparkline(days) {
  if (!days?.length) return '';
  const maxVal = Math.max(...days.map(d => d.snow), 0.5);
  const W = 7, GAP = 3, H = 22;
  const bars = days.map((d, i) => {
    const barH = d.snow > 0 ? Math.max(3, Math.round(d.snow / maxVal * H)) : 2;
    const fill = d.snow >= 4 ? '#1d4ed8' : d.snow >= 1 ? '#2b6de9' : d.snow > 0 ? '#93c5fd' : '#dde5f0';
    return `<rect x="${i*(W+GAP)}" y="${H-barH}" width="${W}" height="${barH}" rx="1" fill="${fill}"><title>${d.date}: ${d.snow}"</title></rect>`;
  });
  const svgW = days.length * (W + GAP) - GAP;
  return `<svg width="${svgW}" height="${H}" viewBox="0 0 ${svgW} ${H}" class="snow-sparkline" aria-label="7-day snowfall chart">${bars.join('')}</svg>`;
}

// ═══════════════════════════════════════════════════════════════════════════════
// "SHOULD I GO?" VERDICT ENGINE
// ═══════════════════════════════════════════════════════════════════════════════

// Environmental lapse rate: ~3.5°F per 1000 ft elevation gain
function summitTempF(baseTempF, baseElevFt, summitElevFt) {
  return baseTempF - ((summitElevFt - baseElevFt) / 1000) * 3.5;
}

function computeVerdict(resorts) {
  const plan = getPlanningWindow();
  const verdictCap = HOW_FAR_TIERS[state.howFar]?.cap ?? 180;
  const verdictPool = (state.origin && verdictCap < Infinity)
    ? resorts.filter(r => { const m = getDriveMins(r.id); return m === null || m <= verdictCap; })
    : resorts;
  const withWx = verdictPool.filter(r => state.weatherCache[r.id]?.data);
  if (!withWx.length) return null;

  const w = normalizedWeights();
  const ranked = withWx.map(r => {
    const wx = state.weatherCache[r.id].data;
    return {
      resort: r,
      wx,
      breakdown: plannerScoreBreakdown(r, wx, null, w),
    };
  }).sort((a, b) => b.breakdown.score - a.breakdown.score);

  const { resort, breakdown } = ranked[0];
  const weatherWindow = breakdown.weatherWindow || weatherWindowIndex(resort, state.weatherCache[resort.id]?.data, plan);
  const primary = weatherWindow.primary || {};
  const tomorrowIn = weatherWindow.primarySnow || 0;
  const stormTotal = weatherWindow.windowSnow || 0;
  const drive = getDriveMins(resort.id);
  const driveText = drive !== null ? formatDrive(resort.id) : '';

  const { summitHi, summitLo } = summitForecastTemps(resort, primary);
  const baseHi = primary.hi ?? null;
  const rainLikely = (summitHi != null && summitHi > SCORING.THAW_TEMP) || (baseHi != null && baseHi >= SCORING.BASE_RAIN_TEMP);
  const warmCaution = !rainLikely && summitHi != null && summitHi > 30;
  const coldSnow = summitHi != null && summitHi <= 24;
  const cond = conditionsCache.get(resort.id)?.data || null;

  let tier, icon, headline, detail;
  const subPoints = [];
  const windowLabel = plan.label;

  if (rainLikely) {
    tier = 'bad';
    icon = '<i class="bi bi-x-circle" style="color:var(--danger)"></i>';
    headline = `Warm weather risk for ${windowLabel}`;
    detail = `${esc(resort.name)} lines up best overall, but temperatures are borderline warm. Double-check conditions before you go.`;
  } else if (tomorrowIn >= 4 || stormTotal >= 6) {
    tier = 'great';
    icon = '<i class="bi bi-check-circle-fill" style="color:#059669"></i>';
    headline = `Best setup for ${windowLabel}`;
    detail = tomorrowIn >= 4
      ? `${tomorrowIn.toFixed(1)}" expected in the next ski window at ${esc(resort.name)}. Fresh snow plus good temps make this the best bet.`
      : `${stormTotal.toFixed(1)}" is lined up across ${windowLabel} at ${esc(resort.name)}. This is the strongest forecast in your result set.`;
  } else if (weatherWindow.score >= 0.64) {
    tier = 'good';
    icon = '<i class="bi bi-check-circle" style="color:var(--accent)"></i>';
    headline = `Solid call for ${windowLabel}`;
    detail = stormTotal >= 1
      ? `${stormTotal.toFixed(1)}" is forecast in the next ski window at ${esc(resort.name)}. Not a powder day, but the mix of snow, temps, and fit makes it the top pick.`
      : `${esc(resort.name)} stands out more for skiable temps, current conditions, and overall fit than for new snow. It looks like the strongest all-around choice for ${windowLabel}.`;
  } else {
    tier = 'marginal';
    icon = '<i class="bi bi-dash-circle" style="color:var(--accent-warm)"></i>';
    headline = `Manage expectations for ${windowLabel}`;
    detail = `${esc(resort.name)} is still the best match for your filters, but forecast support is limited. Expect more groomer skiing than storm skiing.`;
  }

  if (summitHi != null) subPoints.push(`Summit temperatures should be around ${Math.round(summitHi)}°F`);
  if (coldSnow) subPoints.push('Cold enough for drier snow quality');
  else if (warmCaution) subPoints.push('Snow may turn softer later in the day');
  if (cond?.trailsOpen != null && cond?.trailsTotal) subPoints.push(`${cond.trailsOpen}/${cond.trailsTotal} trails currently open`);
  else if (cond?.baseDepth != null) subPoints.push(`${cond.baseDepth}" reported base depth`);

  return {
    tier, icon, headline, detail, subPoints,
    resort, breakdown, drive, driveText,
    tomorrowIn, stormTotal, histTotal: null, histDays: null,
    plan,
  };
}

function renderVerdict(resorts) {
  if (!els.verdictSection || !els.verdictCard) return;
  const v = computeVerdict(resorts);
  if (!v) {
    els.verdictCard.innerHTML = `<div class="verdict-placeholder">
      <div class="verdict-placeholder-icon">⏳</div>
      <div class="verdict-placeholder-text">Loading weather for your top picks…</div>
    </div>`;
    return;
  }

  const { tier, headline, detail, subPoints, resort, breakdown, driveText, plan } = v;
  const brief = buildDecisionBrief(resorts);
  const { context, top5 } = brief;
  const runList = top5.slice(1, 5);
  const subList = subPoints.length
    ? `<ul class="verdict-points">${subPoints.map(p => `<li>${p}</li>`).join('')}</ul>` : '';
  const noOrigin = !state.origin
    ? `<p class="verdict-no-origin"><i class="bi bi-geo-alt"></i> Set your starting location for drive times and distance-weighted picks.</p>` : '';

  const tierLabels = ['Day Trip (≤3h)', 'Weekend (≤6h)', 'All Distances'];
  const driveBanner = state.origin
    ? `<div class="verdict-drive-banner${state.howFar === 2 ? ' verdict-drive-banner--off' : ''}">
        <span class="vdb-label"><i class="bi bi-geo-alt-fill"></i> How Far Will You Go?</span>
        <span class="vdb-tiers">
          ${[0,1,2].map(i =>
            `<button class="vdb-tier-btn${state.howFar === i ? ' active' : ''}" data-tier="${i}">${tierLabels[i]}</button>`
          ).join('')}
        </span>
       </div>`
    : '';

  const inlineWebsite = resort.website
    ? `<a class="verdict-website-link verdict-website-link--inline" href="${resort.website}" target="_blank" rel="noopener">Website ↗</a>`
    : '';

  const alsoRunningHtml = runList.length
    ? `<div class="verdict-top5 verdict-running-list">
        <div class="verdict-top5-label">Also In the Running</div>
        <div class="verdict-running-items">${runList.map(item => {
          const drive = formatDrive(item.resort.id);
          const driveLine = drive && drive !== '—' ? drive : 'Drive not set';
          return `<button class="verdict-running-item verdict-resort-link" data-resort-id="${item.resort.id}">
            <span class="verdict-running-name">${esc(item.resort.name)}</span>
            <span class="verdict-running-meta">${esc(item.resort.passGroup)} · ${esc(driveLine)}</span>
          </button>`;
        }).join('')}</div>
      </div>`
    : '';

  els.verdictCard.innerHTML = `
    <div class="verdict-inner verdict-${tier}">
      ${driveBanner}
      <div class="verdict-left">
        <div class="verdict-pick-block">
          <div class="verdict-pick-label">Top Pick</div>
          <div class="verdict-pick-row">
            <button class="verdict-pick-name verdict-pick-link" id="verdictPickBtn">${esc(resort.name)}</button>
            ${inlineWebsite}
          </div>
          <div class="verdict-pick-meta">${esc(resort.state)} · ${esc(resort.passGroup)}${driveText ? ' · ' + esc(driveText) : ''}</div>
        </div>
        <div id="verdictWriteupSlot" class="verdict-writeup verdict-writeup--loading"></div>
        <div class="verdict-weather-title">Weather Forecast</div>
        <div class="verdict-body">
          <div class="verdict-context-headline">${esc(context.headline)}</div>
          <div class="verdict-headline verdict-headline-${tier}">${headline}</div>
          <div class="verdict-detail">${detail}</div>
          ${subList}
          ${noOrigin}
        </div>
      </div>
      <div class="verdict-right">
        ${alsoRunningHtml}
        <div class="verdict-action-row">
          <button class="btn btn-outline verdict-compare-btn" id="verdictCompareBtn">Compare Mountains</button>
          <button class="btn btn-outline verdict-share-btn" id="verdictShareBtn">Share Pick</button>
        </div>
      </div>
    </div>`;

  const shareBtn = $('verdictShareBtn');
  if (shareBtn) shareBtn.addEventListener('click', () => shareVerdict(resort, v));
  const pickBtn = $('verdictPickBtn');
  if (pickBtn) pickBtn.addEventListener('click', () => {
    state.selectedId = resort.id;
    renderDetail({ scroll: true });
    fetchConditionsForDetail(resort);
  });

  els.verdictCard.querySelectorAll('.verdict-resort-link[data-resort-id]').forEach(btn => {
    btn.addEventListener('click', () => {
      const r = RESORTS.find(x => x.id === btn.dataset.resortId);
      if (!r) return;
      state.selectedId = r.id;
      renderDetail({ scroll: true });
      fetchConditionsForDetail(r);
    });
  });

  injectVerdictWriteup(v);

  const compareBtn = $('verdictCompareBtn');
  if (compareBtn) compareBtn.addEventListener('click', () => {
    const sec = document.getElementById('compareSection');
    if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });

  [0,1,2].forEach(i => {
    const btn = document.querySelector(`.vdb-tier-btn[data-tier="${i}"]`);
    if (btn) btn.addEventListener('click', () => {
      state.howFar = i;
      const tb = document.getElementById('howFarFilter');
      if (tb) tb.value = String(i);
      const resorts = filteredResorts();
      renderVerdict(resorts);
      renderCompareTable(resorts);
      renderCompareTray();
      renderHiddenGems(resorts);
    });
  });
}

function shareVerdict(resort, verdictData) {
  const { stormTotal, driveText } = verdictData;
  const snowText  = stormTotal > 0 ? `${stormTotal.toFixed(1)}" forecast` : 'solid groomed conditions';
  const driveInfo = driveText ? ` · ${driveText} drive` : '';
  const shareText =
    `I'm skiing ${resort.name} (${resort.state}) this weekend — ${snowText}${driveInfo}. ` +
    `Pass: ${resort.passGroup}. Find your mountain →`;
  const p   = serializeState();
  const url = `${location.origin}${location.pathname}${p.toString() ? '?' + p : ''}`;

  if (navigator.share) {
    navigator.share({
      title: `Ski day at ${resort.name} — Where To Ski?!`,
      text:  shareText,
      url,
    }).catch(() => {}); // user cancelled — silent
  } else {
    const full = `${shareText} ${url}`;
    if (navigator.clipboard?.writeText) {
      navigator.clipboard.writeText(full)
        .then(() => showToast('Plan copied — share with your crew!', 3200))
        .catch(() => fallbackCopy(full));
    } else {
      fallbackCopy(full);
    }
  }
}

// ─── Top-level render ─────────────────────────────────────────────────────────
function renderAllCards(resorts) {
  renderSummaryCards(resorts);
  renderActiveFilters();
  renderHiddenGems(resorts);
  renderCompareTable(resorts);
  renderCompareTray();
  renderDetail();
  updateMap(resorts);
  mapModeBtns().forEach(btn => btn.classList.toggle('active', btn.dataset.mapMode === state.mapMode));

  // If weather is already cached, re-render immediately so weight slider changes
  // take effect instantly without hiding the verdict or showing loading placeholders.
  const candidates = plannerCandidates(resorts);
  const hasWeather = resorts.some(r => state.weatherCache[r.id]?.data);

  if (hasWeather) {
    renderVerdict(resorts);
    renderBestDay(resorts);
    _renderStorm(resorts);
  } else {
    // First load — verdict col shows placeholder, other panels show loading
    // bestDaySection removed
    els.stormGrid.innerHTML = '<div class="planner-card">Loading storm data…</div>';
  }

  // Always run async pipeline to catch any missing weather/history and stay fresh
  renderAsyncPanels(resorts);
}

function render() {
  renderAllCards(filteredResorts());
}

// ─── Event wiring ─────────────────────────────────────────────────────────────
const debouncedRender = debounce(render, 50);

function wireEvents() {
  // ── Slider info tooltips ──────────────────────────────────────────────────────
  const SLIDER_TIPS = {
    snow:   'Blends live forecast snow with historical avg snowfall. High = only mountains with genuinely good conditions rank well.',
    size:   'Composite of vertical drop, skiable acres, and longest run. High = big destination mountains rank above small hills.',
    value:  'Rewards lower ticket prices. High = budget-friendly independents outrank expensive resorts regardless of snow.',
    crowds: 'Penalizes busy mountains based on pass network, city proximity, and price. High = quiet independents rise to the top.',
  };
  const tipEl = document.getElementById('sliderTooltip');
  let tipTimeout;
  document.addEventListener('click', e => {
    const btn = e.target.closest('.slider-info-btn');
    if (!btn) { if (tipEl) { tipEl.classList.remove('visible'); } return; }
    e.stopPropagation();
    const key = btn.dataset.tip;
    if (!tipEl || !key || !SLIDER_TIPS[key]) return;
    const rect = btn.getBoundingClientRect();
    tipEl.textContent = SLIDER_TIPS[key];
    tipEl.style.left = Math.min(rect.left + window.scrollX, window.innerWidth - 260) + 'px';
    tipEl.style.top  = (rect.bottom + window.scrollY + 8) + 'px';
    tipEl.classList.add('visible');
    clearTimeout(tipTimeout);
    tipTimeout = setTimeout(() => tipEl.classList.remove('visible'), 8000);
  });

  // ── AI Chat ──────────────────────────────────────────────────────────────────
  if (els.aiChatBtn) {
    els.aiChatBtn.addEventListener('click', () => {
      const q = els.aiChatInput?.value?.trim();
      if (q) askAI(q);
    });
  }
  if (els.aiChatInput) {
    els.aiChatInput.addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        e.preventDefault();
        const q = els.aiChatInput.value?.trim();
        if (q) askAI(q);
      }
    });
  }
  // Jump-to-resort button rendered inside AI result
  if (els.aiChatResult) {
    els.aiChatResult.addEventListener('click', e => {
      const btn = e.target.closest('[data-resort-id]');
      if (!btn) return;
      const id = btn.dataset.resortId;
      state.selectedId = id;
      renderDetail(); // no scroll — we're scrolling to the table row below
      const row = document.querySelector(`tr[data-id="${id}"]`);
      if (row) row.scrollIntoView({ behavior: 'smooth', block: 'center' });
      else {
        const sec = document.getElementById('compareSection');
        if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });
  }

  // ── Mobile card grid delegation ───────────────────────────────────────────
  if (els.mobileCardGrid) {
    els.mobileCardGrid.addEventListener('click', e => {
      // Detail button
      const detailBtn = e.target.closest('[data-mob-detail]');
      if (detailBtn) {
        state.selectedId = detailBtn.dataset.mobDetail;
        renderDetail({ scroll: true });
        const r = RESORTS.find(r => r.id === state.selectedId);
        if (r) fetchConditionsForDetail(r);
        return;
      }
      // Card tap (not checkbox, not button)
      const card = e.target.closest('.mob-card[data-mob-id]');
      if (!card || e.target.closest('input') || e.target.closest('button')) return;
      state.selectedId = card.dataset.mobId;
      renderDetail({ scroll: true });
      const r = RESORTS.find(r => r.id === state.selectedId);
      if (r) fetchConditionsForDetail(r);
    });
    els.mobileCardGrid.addEventListener('change', e => {
      const box = e.target.closest('input[data-compare]');
      if (!box) return;
      if (box.checked) state.compareSet.add(box.dataset.compare);
      else             state.compareSet.delete(box.dataset.compare);
      renderCompareTray();
    });
  }

  // ── Sortable column headers ─────────────────────────────────────────────
  document.querySelectorAll('.sortable-th').forEach(th => {
    th.addEventListener('click', () => {
      const col = th.dataset.sort;
      if (state.sortBy === col) {
        tableSort.dir = tableSort.dir === 'desc' ? 'asc' : 'desc';
      } else {
        state.sortBy = col;
        tableSort.col = col;
        // Default direction: ascending for price/drive/name/state/pass, descending for others
        tableSort.dir = ['price','drive','name','state','pass'].includes(col) ? 'asc' : 'desc';
        if (els.sortBy && [...els.sortBy.options].some(o => o.value === col)) {
          els.sortBy.value = col;
        }
      }
      pushUrlDebounced();
      render();
    });
  });

  els.passFilter.addEventListener('change',     e => { state.passFilter  = e.target.value; pushUrlDebounced(); render(); });
  els.stateFilter.addEventListener('change',    e => { state.stateFilter = e.target.value; pushUrlDebounced(); render(); });
  // How Far Will You Go? toolbar dropdown
  const _howFarFilterEl = document.getElementById('howFarFilter');
  if (_howFarFilterEl) _howFarFilterEl.addEventListener('change', e => {
    state.howFar = Number(e.target.value);
    if (state.howFar < 2 && !state.origin) showToast('Set a starting location for distance filtering');
    // sync verdict tier buttons
    document.querySelectorAll('.vdb-tier-btn').forEach((b,i) => b.classList.toggle('active', i === state.howFar));
    render();
  });

  els.maxDriveFilter.addEventListener('change', e => {
    // legacy — maxDriveFilter DOM element now maps to howFar
    state.maxDrive = Number(e.target.value);
    if (state.maxDrive > 0 && !state.origin) showToast('Set a starting location to use the Drive Time filter');
    pushUrlDebounced(); render();
  });
  if (els.maxPriceFilter) els.maxPriceFilter.addEventListener('change', e => {
    state.priceRange = Number(e.target.value);
    state.maxPrice = 0; // keep legacy field cleared
    pushUrlDebounced(); render();
  });
  els.sortBy.addEventListener('change', e => { state.sortBy = e.target.value; pushUrlDebounced(); render(); });
  els.toggleNight.addEventListener('click', () => {
    state.nightOnly = !state.nightOnly;
    els.toggleNight.setAttribute('aria-pressed', String(state.nightOnly));
    els.toggleNight.textContent = state.nightOnly ? '✓ On' : 'Off';
    pushUrlDebounced(); render();
  });
  if (els.toggleDaytrip) els.toggleDaytrip.addEventListener('click', () => {
    // legacy toggleDaytrip — now handled by howFar; keeping element reference for compat
    state.daytripOnly = !state.daytripOnly;
    els.toggleDaytrip.setAttribute('aria-pressed', String(state.daytripOnly));
    els.toggleDaytrip.textContent = state.daytripOnly ? '✓ On' : 'Off';
    savePlannerState();
    pushUrlDebounced();
    debouncedRender();
  });

  // plannerDetails always visible in new two-column layout
  if (els.plannerDetails) els.plannerDetails.hidden = false;

  // plannerDaytripToggle removed — Day Trip Mode card removed

  function syncPlannerDaytripBtn() {
    const btn = document.getElementById('plannerDaytripToggle');
    if (!btn) return;
    btn.textContent = state.daytripOnly ? 'On' : 'Off';
    btn.classList.toggle('active', state.daytripOnly);
  }
  const plannerDtBtn = document.getElementById('plannerDaytripToggle');
  if (plannerDtBtn) {
    plannerDtBtn.addEventListener('click', () => {
      state.daytripOnly = !state.daytripOnly;
      if (els.toggleDaytrip) els.toggleDaytrip.setAttribute('aria-pressed', String(state.daytripOnly));
      syncPlannerDaytripBtn();
      savePlannerState();
      pushUrlDebounced();
      debouncedRender();
    });
    syncPlannerDaytripBtn();
  }

  // Sticky nav: highlight active section on scroll
  (function initNavHighlight() {
    const sectionIds = ['searchSection','plannerSection','verdictSection','compareSection','stormSection','mapSection'];
    const navLinks   = document.querySelectorAll('.top-nav a[href^="#"]');
    function onScroll() {
      let current = '';
      for (const id of sectionIds) {
        const el = document.getElementById(id);
        if (el && el.getBoundingClientRect().top <= 80) current = id;
      }
      navLinks.forEach(a => {
        const target = a.getAttribute('href').slice(1);
        a.classList.toggle('nav-active', target === current);
      });
    }
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
  })();
  els.resetFilters.addEventListener('click', () => {
    state.search = ''; state.passFilter = 'All'; state.stateFilter = 'All';
    state.sortBy = 'planner'; state.nightOnly = false; state.daytripOnly = false;
    state.maxDrive = 0; state.maxPrice = 0; state.priceRange = 0; state.howFar = 0;
    state.skillLevel = 'mixed'; state.passPreference = 'any'; state.tableSearch = ''; state.tableViewAll = false;
    tableSort = { col: 'planner', dir: 'desc' };
    els.passFilter.value     = 'All';
    els.stateFilter.value    = 'All';
    els.maxDriveFilter.value = '0';
    const _hff = document.getElementById('howFarFilter'); if (_hff) _hff.value = '0';
    // sync verdict tier buttons
    document.querySelectorAll('.vdb-tier-btn').forEach((b,i) => b.classList.toggle('active', i===0));
    if (els.maxPriceFilter) els.maxPriceFilter.value = '0'; state.priceRange = 0;
    els.sortBy.value         = 'planner';
    els.toggleNight.setAttribute('aria-pressed', 'false');
    els.toggleNight.textContent = 'Off';
    // toggleDaytrip legacy removed
    if (els.tableSearch) els.tableSearch.value = '';
    pushUrlDebounced(); render();
  });

  // Table inline search
  if (els.tableSearch) {
    els.tableSearch.addEventListener('input', e => {
      state.tableSearch = e.target.value;
      state.tableViewAll = false;
      renderCompareTable(filteredResorts());
    });
  }

  // View All / Show Top 10 toggle
  if (els.tableViewAllBtn) {
    els.tableViewAllBtn.addEventListener('click', () => {
      state.tableViewAll = !state.tableViewAll;
      renderCompareTable(filteredResorts());
    });
  }

  els.compareBtn.addEventListener('click', renderComparePanel);
  els.clearCompare.addEventListener('click', () => {
    state.compareSet.clear();
    els.comparePanel.classList.add('hidden');
    renderCompareTray();
    render();
  });
  els.closeCompare.addEventListener('click', () => els.comparePanel.classList.add('hidden'));

  // Priority buttons (Low/Medium/High) — replace 1-10 sliders
  document.querySelectorAll('.priority-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const key = btn.closest('.priority-btns')?.dataset.key;
      if (!key) return;
      if (key === 'size') {
        // Vertical is now a hard filter, not a weight
        state.verticalFilter = btn.dataset.val; // 'small' | 'sweet' | 'mid' | 'big'
      } else {
        state.weights[key] = Number(btn.dataset.val);
      }
      state.preset = 'custom';
      savePlannerState();
      syncPlannerControls();
      pushUrlDebounced();
      debouncedRender();
    });
  });

  // Skill level buttons
  document.querySelectorAll('.skill-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      state.skillLevel = btn.dataset.skill;
      state.preset = 'custom';
      savePlannerState();
      syncPlannerControls();
      pushUrlDebounced();
      debouncedRender();
    });
  });

  // Pass preference buttons
  document.querySelectorAll('.pass-pref-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      state.passPreference = btn.dataset.pass;
      state.preset = 'custom';
      savePlannerState();
      syncPlannerControls();
      pushUrlDebounced();
      debouncedRender();
    });
  });
  presetBtns().forEach(btn => btn.addEventListener('click', () => { applyPreset(btn.dataset.preset); pushUrlDebounced(); }));

  mapModeBtns().forEach(btn => btn.addEventListener('click', () => {
    state.mapMode = btn.dataset.mapMode;
    const current = filteredResorts();  // reuse current filtered set
    updateMap(current);
    mapModeBtns().forEach(b => b.classList.toggle('active', b.dataset.mapMode === state.mapMode));
  }));
  // ── Event delegation for compare table and pills (audit #10) ──────────────
  els.comparisonBody.addEventListener('click', e => {
    const row = e.target.closest('tr[data-id]');
    if (!row || e.target.closest('input')) return;
    state.selectedId = row.dataset.id;
    renderDetail({ scroll: true });
    // Priority-fetch this resort's conditions immediately if not yet loaded
    const resort = RESORTS.find(r => r.id === state.selectedId);
    if (resort) fetchConditionsForDetail(resort);
    [...els.comparisonBody.querySelectorAll('tr')].forEach(r =>
      r.classList.toggle('active-row', r.dataset.id === state.selectedId));
  });

  // Prefetch conditions on hover — by the time user clicks, fetch is already in flight
  els.comparisonBody.addEventListener('mouseenter', e => {
    const row = e.target.closest('tr[data-id]');
    if (!row) return;
    const resort = RESORTS.find(r => r.id === row.dataset.id);
    if (resort && resort.website && !conditionsCache.has(resort.id)) {
      fetchConditionsForDetail(resort); // fire-and-forget
    }
  }, true);
  els.comparisonBody.addEventListener('change', e => {
    const box = e.target.closest('input[data-compare]');
    if (!box) return;
    if (box.checked) state.compareSet.add(box.dataset.compare);
    else             state.compareSet.delete(box.dataset.compare);
    renderCompareTray();
  });
  els.comparePills.addEventListener('click', e => {
    const btn = e.target.closest('[data-remove]');
    if (!btn) return;
    state.compareSet.delete(btn.dataset.remove);
    renderCompareTray();
    render();
  });

  // ── Location ────────────────────────────────────────────────────────────────
  const applyLocation = async () => {
    const q = els.originInput.value.trim();
    if (!q) {
      state.origin = null; state.driveCache = {};
      clearSavedOrigin();
      els.locationStatus.textContent = '';
      render(); return;
    }
    els.locationStatus.textContent = 'Finding location…';
    const loc = await geocodeOrigin(q);
    if (loc) {
      state.origin = loc; state.driveCache = {};
      els.locationStatus.textContent = `\u2713 Location set to ${loc.label}`;
      updatePlannerOriginLabel();
      // Scroll to planner so user sees their results, not the hero
      if (els.plannerSection) {
        setTimeout(() => els.plannerSection.scrollIntoView({ behavior: 'smooth', block: 'start' }), 120);
      }
      if (isRememberChecked()) saveOrigin(loc); else clearSavedOrigin();
      pushUrlDebounced();
      await loadDriveTimes();
    } else {
      els.locationStatus.textContent = 'Location not found';
      showToast('Could not find that ZIP or location');
    }
  };
  // Remember my location checkbox
  const _rememberCb = document.getElementById('rememberLocation');
  if (_rememberCb) {
    // Restore checkbox state from localStorage
    const _hadSaved = !!getSavedOrigin();
    _rememberCb.checked = _hadSaved;
    _rememberCb.addEventListener('change', () => {
      if (_rememberCb.checked && state.origin) saveOrigin(state.origin);
      else clearSavedOrigin();
    });
  }

  els.setLocation.addEventListener('click', applyLocation);
  if (els.plannerEditLocation) {
    els.plannerEditLocation.addEventListener('click', () => {
      const heroSection = document.getElementById('searchSection');
      if (heroSection) heroSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
      setTimeout(() => { if (els.originInput) { els.originInput.focus(); els.originInput.select(); } }, 350);
    });
  }
  els.originInput.addEventListener('keydown', async e => { if (e.key === 'Enter') { e.preventDefault(); await applyLocation(); } });
  els.detectLocation.addEventListener('click', () => {
    if (!navigator.geolocation) { showToast('Geolocation not supported'); return; }
    els.locationStatus.textContent = 'Detecting your location…';
    navigator.geolocation.getCurrentPosition(async pos => {
      state.origin = { lat: pos.coords.latitude, lon: pos.coords.longitude, label: 'Your location' };
      els.originInput.value = 'Your location';
      if (isRememberChecked()) saveOrigin(state.origin); else clearSavedOrigin();
      pushUrlDebounced();
      await loadDriveTimes();
      els.locationStatus.textContent = '\u2713 Using your location';
      updatePlannerOriginLabel();
      if (els.plannerSection) {
        setTimeout(() => els.plannerSection.scrollIntoView({ behavior: 'smooth', block: 'start' }), 120);
      }
    }, () => { els.locationStatus.textContent = 'Could not get location'; });
  });

  // ── Back to top — rAF throttled (audit #9) ──────────────────────────────────
  let scrollTicking = false;
  window.addEventListener('scroll', () => {
    if (!scrollTicking) {
      requestAnimationFrame(() => {
        els.backToTop.classList.toggle('show', window.scrollY > 500);
        scrollTicking = false;
      });
      scrollTicking = true;
    }
  });
  els.backToTop.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));
}

// ─── Initialize ───────────────────────────────────────────────────────────────
function initialize() {
  els.passFilter.innerHTML  = UNIQUE_PASSES.map(v => `<option value="${v}">${v}</option>`).join('');
  els.stateFilter.innerHTML = UNIQUE_STATES.map(v => `<option value="${v}">${v}</option>`).join('');

  loadWeatherCache();    // restore session weather cache
  loadHistoryCache();    // restore session history cache
  loadConditionsCache(); // restore session conditions cache

  // Apply URL state before syncing controls — URL wins over localStorage
  const hadUrlState = applyUrlState();
  normalizeWeightsToPriority(); // snap any loaded weights to Low/Medium/High
  updatePlannerOriginLabel(); // show "from [city]" if origin already set
  if (hadUrlState && state.origin) {
    // Restore UI inputs to match URL-decoded state
    els.originInput.value    = state.origin.label;
    els.locationStatus.textContent = `Location set to ${state.origin.label}`;
  } else if (!state.origin) {
    // No URL origin — check if user previously saved their location
    const _saved = getSavedOrigin();
    if (_saved) {
      state.origin = _saved;
      els.originInput.value = _saved.label;
      els.locationStatus.textContent = `Location restored: ${_saved.label}`;
      const _cb = document.getElementById('rememberLocation');
      if (_cb) _cb.checked = true;
    }
  }
  if (hadUrlState) {
    els.passFilter.value     = state.passFilter;
    els.stateFilter.value    = state.stateFilter;
    els.sortBy.value         = state.sortBy;
    els.maxDriveFilter.value = String(state.maxDrive);
    const _hfSync = document.getElementById('howFarFilter'); if (_hfSync) _hfSync.value = String(state.howFar);
    if (els.maxPriceFilter) els.maxPriceFilter.value = String(state.priceRange);
    els.toggleNight.setAttribute('aria-pressed', String(state.nightOnly));
    els.toggleNight.textContent = state.nightOnly ? '✓ On' : 'Off';
    if (els.toggleDaytrip) {
      els.toggleDaytrip.setAttribute('aria-pressed', String(state.daytripOnly));
      els.toggleDaytrip.textContent = state.daytripOnly ? '✓ On' : 'Off';
    }
  }

  syncPlannerControls();
  wireEvents();
  render();

  // Kick off drive time loading if origin came from URL or saved localStorage
  if (state.origin) {
    applyHaversineEstimates();
    loadDriveTimes();
  }

  // Path-based routing — restore resort from /report/<slug> on direct load
  // window.__REPORT_SLUG__ is injected by api/report.js (SSR); fall back to path parsing
  const reportSlug = window.__REPORT_SLUG__ || getReportSlug();
  if (reportSlug) {
    const found = findResortBySlug(reportSlug);
    if (found) {
      state.selectedId = found.id;
      document.title = found.name + ' — Where To Ski?!';
      setTimeout(() => {
        renderDetail();
        const sec = document.getElementById('detailSection');
        if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 600);
    }
  }

  // Browser back/forward — reopen or close the detail card based on URL
  window.addEventListener('popstate', () => {
    const slug = getReportSlug();
    if (slug) {
      const found = findResortBySlug(slug);
      if (found) {
        state.selectedId = found.id;
        document.title = found.name + ' — Where To Ski?!';
        renderDetail({ scroll: true });
        fetchConditionsForDetail(found);
        return;
      }
    }
    // Navigated back to root — close detail card
    state.selectedId = null;
    if (els.detailSection) els.detailSection.classList.add('hidden');
    document.title = 'Where To Ski?!';
    render();
  });

  setTimeout(() => initMap(), 100);
}

initialize();
